const SUBSCRIPTION_KEYWORDS = [
  'subscription', 'renewal', 'renew', 'monthly', 'annual', 'yearly',
  'recurring', 'membership', 'plan', 'billing cycle', 'auto-renew',
  'auto renew', 'next billing', 'trial ended', 'upgraded plan'
];

function isSubscriptionByKeywords(subject, body) {
  const text = ((subject || '') + ' ' + (body || '')).toLowerCase();
  return SUBSCRIPTION_KEYWORDS.some(kw => text.includes(kw));
}

function classify(subject, body, senderKey, seenBefore) {
  const subScore = isSubscriptionByKeywords(subject, body) ? 2 : 0;
  const recurScore = seenBefore ? 2 : 0;
  const total = subScore + recurScore;
  if (total >= 2) {
    return { type: 'Subscriptions', confident: true, reason: [
      subScore > 0 ? 'keyword match' : '',
      recurScore > 0 ? 'recurring sender' : ''
    ].filter(Boolean).join(', ') };
  }
  return { type: 'One-Time', confident: false, reason: 'no strong subscription signals — flagged for review' };
}

const seenSenders = new Set();
try {
  const stored = $getWorkflowStaticData('global');
  if (stored.seenSubscriptionSenders) {
    stored.seenSubscriptionSenders.forEach(s => seenSenders.add(s.toLowerCase()));
  }
} catch(e) {}

const results = [];
for (const item of $input.all()) {
  const subject = item.json.subject || '';
  const body = item.json.text || item.json.snippet || '';
  const from = item.json.from?.value?.[0]?.address || item.json.from?.text || 'unknown';
  const fromName = item.json.from?.value?.[0]?.name || from;
  const date = item.json.date ? new Date(item.json.date) : new Date();
  const year = date.getFullYear().toString();
  const month = (date.getMonth() + 1).toString().padStart(2, '0');

  const emailMatch = from.match(/@([^.]+)/);
  const senderKey = emailMatch ? emailMatch[1] : fromName.replace(/[^a-zA-Z0-9]/g, '_').substring(0, 30);
  const senderFolder = senderKey.charAt(0).toUpperCase() + senderKey.slice(1);

  const subjectLower = subject.toLowerCase();
  let docType = 'Receipts';
  if (subjectLower.includes('invoice') || subjectLower.includes('billing statement')) {
    docType = 'Invoices';
  }

  const seenBefore = seenSenders.has(senderKey.toLowerCase());
  let receiptSubType = 'One-Time';
  let classificationReason = '';
  let needsReview = false;
  if (docType === 'Receipts') {
    const cls = classify(subject, body, senderKey, seenBefore);
    receiptSubType = cls.type;
    classificationReason = cls.reason;
    needsReview = !cls.confident;
  }

  const needsSubTypeFolder = docType === 'Receipts' && receiptSubType === 'Subscriptions';

  const attachmentKeys = Object.keys(item.binary || {}).filter(k => k.startsWith('attachment_'));
  if (attachmentKeys.length > 0) {
    for (const attachKey of attachmentKeys) {
      results.push({
        json: {
          docType,
          receiptSubType,
          needsSubTypeFolder,
          senderFolder,
          year,
          month,
          subject,
          from,
          attachmentKey: attachKey,
          fileName: item.binary[attachKey]?.fileName || attachKey + '.pdf',
          classificationReason,
          needsReview,
          seenBefore
        },
        binary: { data: item.binary[attachKey] }
      });
    }
  }
}
return results;

const items = $input.all();
const meta = items[0];
const match = items.find(i => (i.json.name || '').toLowerCase() === 'subscriptions');
return [{
  json: {
    ...meta.json,
    subTypeFolderId: match ? match.json.id : '',
    subTypeExists: !!match
  },
  binary: meta.binary || {}
}];

const items = $input.all();
const meta = items[0];
const parentForSender = meta.json.subTypeFolderId || meta.json.docTypeFolderId;

if (meta.json.receiptSubType === 'Subscriptions' && meta.json.subTypeFolderId) {
  try {
    const stored = $getWorkflowStaticData('global');
    const seen = stored.seenSubscriptionSenders || [];
    const key = (meta.json.senderFolder || '').toLowerCase();
    if (!seen.map(s => s.toLowerCase()).includes(key)) {
      seen.push(meta.json.senderFolder);
      stored.seenSubscriptionSenders = seen;
    }
  } catch(e) {}
}

return [{
  json: { ...meta.json, parentForSender },
  binary: meta.binary || {}
}];

const items = $input.all();
const meta = items[0];
const senderFolder = (meta.json.senderFolder || '').toLowerCase();

const exactMatch = items.find(i => (i.json.name || '').toLowerCase() === senderFolder);
const partialMatch = !exactMatch
  ? items.find(i => {
      const name = (i.json.name || '').toLowerCase();
      return name.includes(senderFolder) || senderFolder.includes(name);
    })
  : null;

const match = exactMatch || partialMatch;
const senderFolderId = match ? match.json.id : '';

return [{
  json: {
    ...meta.json,
    senderFolderId,
    senderFolderExists: !!senderFolderId,
    matchedFolderName: match ? match.json.name : ''
  },
  binary: meta.binary || {}
}];

const items = $input.all();
const meta = items[0];
const docType = (meta.json.docType || '').toLowerCase();
const match = items.find(i => (i.json.name || '').toLowerCase() === docType);
return [{
  json: {
    ...meta.json,
    docTypeFolderId: match ? match.json.id : '',
    docTypeExists: !!match
  },
  binary: meta.binary || {}
}];
